#include <stdio.h>
struct Account {
    int principal;
    double rate;
};
int main() {
    struct Account acc;
    acc.principal = 9000;
    acc.rate = 0.055;
    double amount = acc.principal;
    for (int i = 0; i < 2; i++) {
        amount = amount + amount * acc.rate;
    }
    int intPart = (int)amount;
    double fracPart = (amount - intPart) * 10000;
    printf("%d and %.2f", intPart, fracPart);
    return 0;
